  "meta_rule.schema": {
    "meta": {
      "id": "string",                 // ident unique de la règle
      "name": "string",
      "family": "data|security|execution|permission|relation|version|status|schedule|logging|trigger|catalog|i18n|audit|remediation",
      "class_scope": ["string"],      // classes cibles (ex: ["Page","User","Scenario"])
      "applies_to": "class|instance|relation|scenario",
      "version": "semver",
      "hash": "sha256",
      "enabled": true,
      "priority": 0,                  // ordre de résolution en cas de conflit
      "tags": ["string"]              // facettes de filtrage (tenant, env, role, locale…)
    },

    "conditions": {
      "tenant": ["string"],
      "roles": ["string"],
      "scopes": ["string"],           // ex: read|create|update|delete|execute|engage
      "environments": ["dev|staging|prod"],
      "locales": ["string"],
      "channels": ["web|api|ext|cli"],
