        "type": "get|execute|validate|render",
        "intention": "read|create|update|delete|execute|engage",
        "operators": ["string"]
      },
      "relations_required": [
        { "type": "string", "cardinality": "one|many", "direction": "in|out|both" }
      ],
      "status_required": ["string"],  // status actuels autorisant l’application
      "when": {                       // filtre déclaratif optionnel (mini-langage)
        "expr": "string"
      }
    },

    "effects": {
      "allow": ["string"],            // actions explicitement autorisées
      "deny": ["string"],             // actions explicitement refusées
      "constraints": [                // contraintes de données et de formes
        { "path": "jsonptr", "type": "string", "required": true, "enum": ["..."], "min": 0, "max": 0, "pattern": "regex" }
      ],
      "defaults": [                   // valeurs par défaut
        { "path": "jsonptr", "value": {} }
      ],
      "transforms": [                 // transformations déterministes
        { "path": "jsonptr", "op": "map|trim|lower|upper|round|remap", "params": {} }
      ],
      "budgets": {                    // limites d’exécution
        "time_ms": { "max": 0 },
        "cpu_pct": { "max": 0 },
