          { "type": "string", "min": 0, "max": 0, "cascade": "none|update|delete" }
        ],
        "invariants": [
          { "name": "string", "check": "expr|ref", "severity": "info|warn|error" }
        ]
      },
      "versioning": {                 // compatibilité
        "compat_min": "semver",
        "deprecated_after": "iso8601",
        "migration": { "scenario": "ident", "params": {} }
      },
      "status": {                     // status universel (familles, allowed, transitions)
        "families": ["lifecycle|execution|availability|compliance"],
        "allowed": ["string"],
        "initial": "string",
        "transitions": [
          {
            "from": "string",
            "to": "string",
            "conditions": { "permissions": ["string"], "rules": ["string"], "invariants": ["string"] },
            "effects": { "notify": ["role|user"], "hooks": ["onSuccess|onFailure"] }
          }
        ]
      },
      "schedule": {                   // planification
        "rrule": "string",
        "start_at": "iso8601",
        "end_at": "iso8601",
        "timezone": "IANA",
