import json, sys, time, importlib, hashlib, os
from pathlib import Path

def read_json(p): return json.loads(Path(p).read_text(encoding="utf-8"))

def sha(obj): return hashlib.sha256(json.dumps(obj, sort_keys=True).encode()).hexdigest()

def load_catalogs(root="catalogs"):
    root = Path(root)
    manifest = read_json(root / "manifest.json")
    # charge tous les fichiers référencés par le manifest
    def _load(ref):
        p = root / ref
        if p.is_dir():
            data = {}
            for f in sorted(p.glob("*.json")):
                data[f.stem] = read_json(f)
            return data
        return read_json(p)
    catalogs = {}
    for k, ref in manifest["includes"].items():
        catalogs[k] = _load(ref)

